     1→/**
     2→ * MesoLayer - DNA-like task block visualization
     3→ *
     4→ * Renders task blocks using InstancedMesh for optimal performance.
     5→ * Visible at zoom levels 0.5x - 2.0x (MESO LOD level).
     6→ *
     7→ * Features:
     8→ * - InstancedMesh for all task blocks (single draw call)
     9→ * - Color coding: blue (maintenance), orange (overhaul), gray (inspection)
    10→ * - Conflict indicators: red border effect on hasConflict tasks
    11→ * - Alternating row backgrounds for readability
    12→ */
    13→
    14→import { useMemo, useRef, useEffect } from 'react';
    15→import { InstancedMesh, Object3D, Color, Matrix4 } from 'three';
    16→import type { TaskRender } from '../../data/types';
    17→import { DEFAULT_VIEW_CONFIG } from '../../data/types';
    18→
    19→interface MesoLayerProps {
    20→  tasks: TaskRender[];
    21→  trainCount: number;
    22→  /** Opacity for LOD transitions (0-1). Default: 1 */
    23→  opacity?: number;
    24→  /** Currently hovered task ID for highlight effect */
    25→  hoveredTaskId?: string | null;
    26→  /** Currently selected task ID for selection highlight (F019) */
    27→  selectedTaskId?: string | null;
    28→  /** Currently keyboard-focused task ID for focus indicator (F021) */
    29→  focusedTaskId?: string | null;
    30→}
    31→
    32→// Color palette matching POC reference
    33→const COLORS: Record<string, string> = {
    34→  blue: '#3b82f6',    // maintenance
    35→  orange: '#f59e0b',  // overhaul
    36→  gray: '#9ca3af',    // inspection
    37→};
    38→
    39→const CONFLICT_COLOR = '#ef4444'; // red for conflicts
    40→
    41→// Row background colors (alternating)
    42→const ROW_BG_EVEN = '#ffffff';
    43→const ROW_BG_ODD = '#f8fafc';
    44→
    45→const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;
    46→
    47→// Task block height (with padding)
    48→const TASK_HEIGHT = pxPerTrain - 4; // 20px height with 2px padding top/bottom
    49→const TASK_PADDING_Y = 2;
    50→
    51→/**
    52→ * Renders alternating row backgrounds for train rows using InstancedMesh
    53→ * OPTIMIZED: Single draw call instead of 50 individual meshes
    54→ */
    55→function RowBackgrounds({
    56→  trainCount,
    57→  totalDays,
    58→  opacity = 1,
    59→}: {
    60→  trainCount: number;
    61→  totalDays: number;
    62→  opacity?: number;
    63→}) {
    64→  const totalWidth = totalDays * pxPerDay;
    65→  const meshRef = useRef<InstancedMesh>(null);
    66→  const tempObject = useMemo(() => new Object3D(), []);
    67→
    68→  useEffect(() => {
    69→    if (!meshRef.current || trainCount === 0) return;
    70→
    71→    const mesh = meshRef.current;
    72→
    73→    for (let i = 0; i < trainCount; i++) {
    74→      tempObject.position.set(
    75→        totalWidth / 2, // Center the row
    76→        -i * pxPerTrain - pxPerTrain / 2, // Y position (negative = down)
    77→        -0.1 // Behind tasks
    78→      );
    79→      tempObject.scale.set(totalWidth, pxPerTrain, 1);
    80→      tempObject.updateMatrix();
    81→      mesh.setMatrixAt(i, tempObject.matrix);
    82→      mesh.setColorAt(i, new Color(i % 2 === 0 ? ROW_BG_EVEN : ROW_BG_ODD));
    83→    }
    84→
    85→    mesh.instanceMatrix.needsUpdate = true;
    86→    if (mesh.instanceColor) {
    87→      mesh.instanceColor.needsUpdate = true;
    88→    }
    89→  }, [trainCount, totalWidth, tempObject]);
    90→
    91→  if (trainCount === 0) return null;
    92→
    93→  return (
    94→    <instancedMesh ref={meshRef} args={[undefined, undefined, trainCount]}>
    95→      <planeGeometry args={[1, 1]} />
    96→      <meshBasicMaterial transparent opacity={0.5 * opacity} />
    97→    </instancedMesh>
    98→  );
    99→}
   100→
   101→// Highlight color multiplier for hovered tasks
   102→// Using high value for clear visual feedback
   103→const HOVER_BRIGHTNESS = 1.8;
   104→
   105→// Selection indicator color (distinct cyan/teal)
   106→const SELECTION_COLOR = '#06b6d4'; // cyan-500
   107→
   108→// Focus indicator color (F021 - keyboard focus)
   109→// Using a distinct purple for focus to differentiate from selection
   110→const FOCUS_COLOR = '#8b5cf6'; // violet-500
   111→
   112→/**
   113→ * Brighten a color for hover effect
   114→ */
   115→function brightenColor(hexColor: string, factor: number): Color {
   116→  const color = new Color(hexColor);
   117→  color.r = Math.min(1, color.r * factor);
   118→  color.g = Math.min(1, color.g * factor);
   119→  color.b = Math.min(1, color.b * factor);
   120→  return color;
   121→}
   122→
   123→/**
   124→ * Main task blocks using InstancedMesh
   125→ */
   126→function TaskBlocks({
   127→  tasks,
   128→  opacity = 1,
   129→  hoveredTaskId,
   130→  selectedTaskId,
   131→  focusedTaskId,
   132→}: {
   133→  tasks: TaskRender[];
   134→  opacity?: number;
   135→  hoveredTaskId?: string | null;
   136→  selectedTaskId?: string | null;
   137→  focusedTaskId?: string | null;
   138→}) {
   139→  const meshRef = useRef<InstancedMesh>(null);
   140→  const tempObject = useMemo(() => new Object3D(), []);
   141→  const tempColor = useMemo(() => new Color(), []);
   142→
   143→  // Update instance matrices and colors when tasks change or hover/selection/focus changes
   144→  useEffect(() => {
   145→    if (!meshRef.current) return;
   146→
   147→    const mesh = meshRef.current;
   148→
   149→    tasks.forEach((task, i) => {
   150→      // Calculate position and size
   151→      const width = task.duration * pxPerDay;
   152→      const height = TASK_HEIGHT;
   153→      const x = task.startDay * pxPerDay + width / 2; // Center of task
   154→      const y = -task.trainIndex * pxPerTrain - pxPerTrain / 2; // Negative Y (down)
   155→      // Z ordering: selected > focused > conflict > hovered > normal
   156→      const isSelected = task.id === selectedTaskId;
   157→      const isFocused = task.id === focusedTaskId;
   158→      const isHovered = task.id === hoveredTaskId;
   159→      const z = isSelected ? 0.2 : isFocused ? 0.15 : task.hasConflict ? 0.1 : isHovered ? 0.05 : 0;
   160→
   161→      // Set transform
   162→      tempObject.position.set(x, y, z);
   163→      tempObject.scale.set(width, height, 1);
   164→      tempObject.updateMatrix();
   165→      mesh.setMatrixAt(i, tempObject.matrix);
   166→
   167→      // Set color: selected gets distinct color, focused gets focus color, hovered gets brightened, normal is base
   168→      if (isSelected) {
   169→        tempColor.set(SELECTION_COLOR);
   170→        mesh.setColorAt(i, tempColor);
   171→      } else if (isFocused) {
   172→        // Focus uses a distinct purple color to differentiate from selection and hover
   173→        tempColor.set(FOCUS_COLOR);
   174→        mesh.setColorAt(i, tempColor);
   175→      } else if (isHovered) {
   176→        const baseColor = task.hasConflict ? CONFLICT_COLOR : COLORS[task.color];
   177→        const brightened = brightenColor(baseColor, HOVER_BRIGHTNESS);
   178→        mesh.setColorAt(i, brightened);
   179→      } else {
   180→        const baseColor = task.hasConflict ? CONFLICT_COLOR : COLORS[task.color];
   181→        tempColor.set(baseColor);
   182→        mesh.setColorAt(i, tempColor);
   183→      }
   184→    });
   185→
   186→    // Mark buffers for update
   187→    mesh.instanceMatrix.needsUpdate = true;
   188→    if (mesh.instanceColor) {
   189→      mesh.instanceColor.needsUpdate = true;
   190→    }
   191→  }, [tasks, tempObject, tempColor, hoveredTaskId, selectedTaskId, focusedTaskId]);
   192→
   193→  if (tasks.length === 0) {
   194→    return null;
   195→  }
   196→
   197→  return (
   198→    <instancedMesh
   199→      ref={meshRef}
   200→      args={[undefined, undefined, tasks.length]}
   201→    >
   202→      {/* Unit plane centered at origin - will be scaled by instance matrix */}
   203→      <planeGeometry args={[1, 1]} />
   204→      <meshBasicMaterial toneMapped={false} transparent={opacity < 1} opacity={opacity} />
   205→    </instancedMesh>
   206→  );
   207→}
   208→
   209→/**
   210→ * Conflict glow effect layer
   211→ * Renders a subtle glow behind conflict tasks
   212→ */
   213→function ConflictGlows({ tasks, opacity = 1 }: { tasks: TaskRender[]; opacity?: number }) {
   214→  const conflictTasks = useMemo(
   215→    () => tasks.filter((t) => t.hasConflict),
   216→    [tasks]
   217→  );
   218→
   219→  const meshRef = useRef<InstancedMesh>(null);
   220→  const tempObject = useMemo(() => new Object3D(), []);
   221→
   222→  useEffect(() => {
   223→    if (!meshRef.current || conflictTasks.length === 0) return;
   224→
   225→    const mesh = meshRef.current;
   226→
   227→    conflictTasks.forEach((task, i) => {
