     1→/**
     2→ * Mock Data Generator
     3→ *
     4→ * Generates test data for the MMS visualization:
     5→ * - 50 trains (30 ALSTOM + 20 KINKI)
     6→ * - 10 years of tasks per train
     7→ * - ~10-12 tasks per train per year
     8→ * - ~5% of tasks have conflict flags
     9→ */
    10→
    11→import type {
    12→  Train,
    13→  Task,
    14→  TaskRender,
    15→  GeneratedData,
    16→  DatasetMeta,
