    71→  duration: number;        // Width (days)
    72→  color: TaskColor;        // Derived from Task.type
    73→  hasConflict: boolean;    // Passthrough from Task
    74→  type: TaskType;          // For label display in MicroLayer
    75→  predecessorId?: string;  // Optional: ID of predecessor task (F023)
    76→}
    77→
    78→export const TYPE_TO_COLOR: Record<TaskType, TaskColor> = {
    79→  maintenance: 'blue',
    80→  overhaul: 'orange',
    81→  inspection: 'gray',
    82→};
    83→
    84→// ─────────────────────────────────────────────────────────────
    85→// WORLD BOUNDS (Navigation limits)
    86→// ─────────────────────────────────────────────────────────────
    87→
    88→/**
    89→ * Defines the navigable world boundaries.
    90→ * Camera will be clamped to these bounds.
    91→ *
    92→ * Coordinate system:
    93→ * - X: 0 = first day, positive = future
    94→ * - Y: 0 = top (TRAIN-001), negative = down (more trains)
    95→ */
    96→export interface WorldBounds {
    97→  minX: number;  // 0 (first day)
    98→  maxX: number;  // totalDays * pxPerDay
    99→  minY: number;  // -trainCount * pxPerTrain (bottom)
   100→  maxY: number;  // 0 (top)
   101→}
   102→
   103→// ─────────────────────────────────────────────────────────────
   104→// CANVAS CONFIGURATION
   105→// ─────────────────────────────────────────────────────────────
   106→
   107→export interface ViewConfig {
   108→  pxPerDay: number;        // Pixels per day (X scale)
   109→  pxPerTrain: number;      // Pixels per train row (Y scale)
   110→  minZoom: number;         // Minimum zoom level
   111→  maxZoom: number;         // Maximum zoom level
   112→  zoomSensitivity: number; // Scroll sensitivity
   113→  lodThresholds: {
   114→    macro: number;         // Below this → MACRO view
   115→    micro: number;         // Above this → MICRO view
   116→  };
   117→}
   118→
   119→export type LODLevel = 'MACRO' | 'MESO' | 'MICRO';
   120→
   121→export interface ViewportState {
   122→  zoom: number;
   123→  panX: number;
   124→  panY: number;
   125→  lod: LODLevel;
   126→}
   127→
   128→// ─────────────────────────────────────────────────────────────
   129→// DEFAULT VALUES
   130→// ─────────────────────────────────────────────────────────────
   131→
   132→export const DEFAULT_VIEW_CONFIG: ViewConfig = {
   133→  pxPerDay: 10,
   134→  pxPerTrain: 24,
   135→  minZoom: 0.1,
   136→  maxZoom: 5,
   137→  zoomSensitivity: 0.002,
   138→  lodThresholds: {
   139→    macro: 0.5,
   140→    micro: 2.0,
   141→  },
   142→};
   143→
   144→export const DEFAULT_DATASET_META: DatasetMeta = {
   145→  startDate: '2024-01-01',
   146→  trainCount: 50,
   147→  years: 10,
   148→};
   149→
   150→/**
   151→ * Calculate world bounds from dataset metadata
   152→ */
   153→export function calculateWorldBounds(
   154→  trainCount: number,
   155→  totalDays: number,
   156→  config: ViewConfig = DEFAULT_VIEW_CONFIG
   157→): WorldBounds {
   158→  return {
   159→    minX: 0,
   160→    maxX: totalDays * config.pxPerDay,
   161→    minY: -trainCount * config.pxPerTrain,
   162→    maxY: 0,
   163→  };
   164→}
   165→
   166→/**
   167→ * Data bounds with padding for visualization
   168→ */
   169→export interface DataBounds {
   170→  minX: number;
   171→  maxX: number;
   172→  minY: number;
   173→  maxY: number;
   174→  width: number;
   175→  height: number;
   176→  centerX: number;
   177→  centerY: number;
   178→}
   179→
   180→/**
   181→ * Calculate actual data bounds from tasks (not theoretical world bounds)
   182→ * This is used to fit the initial view to the actual data range.
   183→ *
   184→ * @param tasks - Array of rendered tasks with position data
   185→ * @param trainCount - Total number of trains
   186→ * @param config - View configuration
   187→ * @param padding - Padding in pixels around the data bounds
   188→ */
   189→export function calculateDataBounds(
   190→  tasks: TaskRender[],
   191→  trainCount: number,
   192→  config: ViewConfig = DEFAULT_VIEW_CONFIG,
   193→  padding: number = 50
   194→): DataBounds {
   195→  if (tasks.length === 0) {
   196→    // No tasks, return default bounds
   197→    return {
   198→      minX: 0,
   199→      maxX: config.pxPerDay * 365,
   200→      minY: -trainCount * config.pxPerTrain,
   201→      maxY: 0,
   202→      width: config.pxPerDay * 365,
   203→      height: trainCount * config.pxPerTrain,
   204→      centerX: (config.pxPerDay * 365) / 2,
   205→      centerY: (-trainCount * config.pxPerTrain) / 2,
   206→    };
   207→  }
   208→
   209→  // Find min/max from actual task positions
   210→  let minStartDay = Infinity;
   211→  let maxEndDay = -Infinity;
   212→  let minTrainIndex = Infinity;
   213→  let maxTrainIndex = -Infinity;
   214→
   215→  for (const task of tasks) {
   216→    minStartDay = Math.min(minStartDay, task.startDay);
   217→    maxEndDay = Math.max(maxEndDay, task.startDay + task.duration);
   218→    minTrainIndex = Math.min(minTrainIndex, task.trainIndex);
   219→    maxTrainIndex = Math.max(maxTrainIndex, task.trainIndex);
   220→  }
   221→
   222→  // Convert to pixel coordinates
   223→  const minX = minStartDay * config.pxPerDay - padding;
   224→  const maxX = maxEndDay * config.pxPerDay + padding;
   225→  // Y is negative (trains go downward)
   226→  const maxY = -minTrainIndex * config.pxPerTrain + padding;
   227→  const minY = -(maxTrainIndex + 1) * config.pxPerTrain - padding;
   228→
   229→  const width = maxX - minX;
   230→  const height = maxY - minY;
   231→
   232→  return {
   233→    minX,
   234→    maxX,
   235→    minY,
   236→    maxY,
   237→    width,
   238→    height,
   239→    centerX: minX + width / 2,
   240→    centerY: minY + height / 2,
   241→  };
   242→}
   243→
   244→/**
   245→ * Calculate initial camera position and zoom to fit data bounds in viewport
   246→ *
   247→ * Follows the pattern used by D3.js fitExtent, Gantt chart zoomToFit, and pixi-viewport fitWorld
   248→ *
   249→ * Strategy:
   250→ * - If data fits comfortably at reasonable zoom (0.5x - 1.5x), fit all data
   251→ * - If data is too large (would require < 0.5x zoom), show starting portion at 0.5x zoom
   252→ * - This provides a good initial UX while allowing users to zoom out for full overview
   253→ *
   254→ * @param dataBounds - The data bounds to fit
   255→ * @param viewportWidth - Viewport width in pixels
   256→ * @param viewportHeight - Viewport height in pixels
   257→ * @param maxZoom - Maximum zoom level (for performance/UX)
   258→ * @param minZoom - Minimum zoom level for initial view
   259→ */
   260→export function calculateFitToView(
   261→  dataBounds: DataBounds,
   262→  viewportWidth: number,
   263→  viewportHeight: number,
   264→  maxZoom: number = 1.5,
   265→  minZoom: number = 0.5
   266→): { cameraX: number; cameraY: number; zoom: number } {
   267→  // Calculate zoom needed to fit all data in viewport
   268→  const zoomX = viewportWidth / dataBounds.width;
   269→  const zoomY = viewportHeight / dataBounds.height;
   270→  const fitAllZoom = Math.min(zoomX, zoomY);
   271→
   272→  // Clamp zoom to reasonable initial range
   273→  const zoom = Math.max(minZoom, Math.min(maxZoom, fitAllZoom));
   274→
   275→  // If we can fit all data at the calculated zoom, center on data
   276→  if (fitAllZoom >= minZoom) {
   277→    return {
   278→      cameraX: dataBounds.centerX,
   279→      cameraY: dataBounds.centerY,
   280→      zoom,
   281→    };
   282→  }
   283→
   284→  // Data is too large - show starting portion (top-left of data bounds)
   285→  // Calculate camera position to show left edge and top of data
   286→  const halfViewX = viewportWidth / 2 / zoom;
   287→  const halfViewY = viewportHeight / 2 / zoom;
   288→
   289→  return {
   290→    cameraX: dataBounds.minX + halfViewX,
   291→    cameraY: dataBounds.maxY - halfViewY, // maxY is the top (less negative)
   292→    zoom,
   293→  };
   294→}
   295→
   296→// ─────────────────────────────────────────────────────────────
   297→// FUTURE EXTENSIONS (Optional Fields)
   298→// These fields can be added without breaking existing code.
   299→// ─────────────────────────────────────────────────────────────
   300→
   301→// Extended Train (future)
   302→export interface TrainExtended extends Train {
   303→  carsCount?: number;
   304→  currentMileageKm?: number;
   305→  avgDailyMileageKm?: number;
   306→  status?: 'operational' | 'maintenance' | 'out-of-service';
   307→}
   308→
   309→// Extended Task (future)
   310→export interface TaskExtended extends Task {
   311→  maintenanceLevel?: MaintenanceLevel;
   312→  manHours?: number;
   313→  estimatedCost?: number;
   314→  dependencies?: string[];
   315→  status?: 'scheduled' | 'in-progress' | 'completed';
   316→}
   317→
   318→// Conflict as separate entity (future)
   319→export interface Conflict {
   320→  id: string;
   321→  taskIds: [string, string];
   322→  type: 'overlap' | 'resource' | 'dependency';
   323→  severity: 'low' | 'medium' | 'high';
   324→  description?: string;
   325→}
   326→

