   120→/**
   121→ * Get days until next unit
   122→ */
   123→function getDaysPerUnit(granularity: Granularity): number {
   124→  switch (granularity) {
   125→    case 'year':
   126→      return 365;
   127→    case 'month':
   128→      return 30;
   129→    case 'week':
   130→      return 7;
   131→    case 'day':
