     1→/**
     2→ * Minimap Component (F025, BUG-004)
     3→ *
     4→ * A bird's eye view minimap showing the entire canvas at small scale.
     5→ * Features:
     6→ * - Shows simplified task density (heatmap-like visualization)
     7→ * - Displays viewport rectangle indicating current visible area
     8→ * - Click/drag on minimap to navigate
     9→ * - Always visible (Google Maps style) - no toggle
    10→ *
    11→ * Positioned in the bottom-right corner of the canvas.
    12→ */
    13→
    14→import { useCallback, useMemo, useRef, useState, useEffect } from 'react';
    15→import { Card } from '@blueprintjs/core';
    16→import type { TaskRender } from '../data/types';
    17→import { DEFAULT_VIEW_CONFIG } from '../data/types';
    18→
    19→const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;
    20→
    21→// Minimap dimensions
    22→const MINIMAP_WIDTH = 200;
    23→const MINIMAP_HEIGHT = 80;
    24→const MINIMAP_PADDING = 4;
    25→
    26→// Colors
    27→const MINIMAP_BG = '#e8e8e8';
    28→const VIEWPORT_RECT_COLOR = 'rgba(59, 130, 246, 0.3)'; // blue-500 with opacity
    29→const VIEWPORT_RECT_BORDER = '#3b82f6'; // blue-500
    30→const TASK_COLOR_LOW = '#fef3c7'; // amber-100
    31→const TASK_COLOR_HIGH = '#dc2626'; // red-600
    32→
    33→interface MinimapProps {
    34→  /** Total number of trains */
    35→  trainCount: number;
    36→  /** Total number of days in the timeline */
    37→  totalDays: number;
    38→  /** Tasks for rendering density visualization */
    39→  tasks: TaskRender[];
    40→  /** Current camera X position (world coordinates) */
    41→  cameraX: number;
    42→  /** Current camera Y position (world coordinates) */
    43→  cameraY: number;
    44→  /** Current zoom level */
    45→  zoom: number;
    46→  /** Canvas width in pixels */
    47→  canvasWidth: number;
    48→  /** Canvas height in pixels */
    49→  canvasHeight: number;
    50→  /** Callback when user clicks/drags on minimap to navigate */
    51→  onNavigate: (worldX: number, worldY: number) => void;
    52→  // BUG-004: Removed visible and onToggle - minimap is now always visible (Google Maps style)
    53→}
    54→
    55→/**
    56→ * Convert world coordinates to minimap coordinates
    57→ */
    58→function worldToMinimap(
    59→  worldX: number,
    60→  worldY: number,
    61→  worldWidth: number,
    62→  worldHeight: number
    63→): { x: number; y: number } {
    64→  const x = (worldX / worldWidth) * MINIMAP_WIDTH;
    65→  // Y is negative in world (trains go down), convert to positive for minimap
    66→  const y = (-worldY / worldHeight) * MINIMAP_HEIGHT;
    67→  return { x, y };
    68→}
    69→
    70→/**
    71→ * Convert minimap coordinates to world coordinates
    72→ */
    73→function minimapToWorld(
    74→  minimapX: number,
    75→  minimapY: number,
    76→  worldWidth: number,
    77→  worldHeight: number
    78→): { worldX: number; worldY: number } {
    79→  const worldX = (minimapX / MINIMAP_WIDTH) * worldWidth;
    80→  // Convert positive minimap Y to negative world Y
    81→  const worldY = -(minimapY / MINIMAP_HEIGHT) * worldHeight;
    82→  return { worldX, worldY };
    83→}
    84→
    85→/**
    86→ * Generate heatmap data for minimap visualization
    87→ * Groups tasks into grid cells and counts density
    88→ */
    89→function generateHeatmapData(
    90→  tasks: TaskRender[],
    91→  totalDays: number,
    92→  trainCount: number,
    93→  gridCols: number,
    94→  gridRows: number
    95→): number[][] {
    96→  // Initialize grid with zeros
    97→  const grid: number[][] = Array(gridRows)
    98→    .fill(null)
    99→    .map(() => Array(gridCols).fill(0));
   100→
   101→  const daysPerCell = totalDays / gridCols;
   102→  const trainsPerCell = trainCount / gridRows;
   103→
   104→  // Count tasks in each cell
   105→  for (const task of tasks) {
   106→    const col = Math.floor(task.startDay / daysPerCell);
   107→    const row = Math.floor(task.trainIndex / trainsPerCell);
   108→
   109→    // Clamp to grid bounds
   110→    const clampedCol = Math.min(gridCols - 1, Math.max(0, col));
   111→    const clampedRow = Math.min(gridRows - 1, Math.max(0, row));
   112→
   113→    grid[clampedRow][clampedCol]++;
   114→  }
   115→
   116→  return grid;
   117→}
   118→
   119→/**
   120→ * Interpolate between two colors based on value (0-1)
   121→ */
   122→function interpolateColor(value: number): string {
   123→  // Clamp value to 0-1
   124→  const t = Math.max(0, Math.min(1, value));
   125→
   126→  // Parse colors
   127→  const lowR = 254, lowG = 243, lowB = 199; // amber-100
   128→  const highR = 220, highG = 38, highB = 38; // red-600
   129→
   130→  // Interpolate
   131→  const r = Math.round(lowR + (highR - lowR) * t);
   132→  const g = Math.round(lowG + (highG - lowG) * t);
   133→  const b = Math.round(lowB + (highB - lowB) * t);
   134→
   135→  return `rgb(${r}, ${g}, ${b})`;
   136→}
   137→
   138→export function Minimap({
   139→  trainCount,
   140→  totalDays,
   141→  tasks,
   142→  cameraX,
   143→  cameraY,
   144→  zoom,
   145→  canvasWidth,
   146→  canvasHeight,
   147→  onNavigate,
   148→}: MinimapProps) {
   149→  const minimapRef = useRef<HTMLDivElement>(null);
   150→  const [isDragging, setIsDragging] = useState(false);
   151→
   152→  // Calculate world dimensions
   153→  const worldWidth = totalDays * pxPerDay;
   154→  const worldHeight = trainCount * pxPerTrain;
   155→
   156→  // Generate heatmap data (coarse grid for performance)
   157→  const gridCols = 40; // Horizontal cells
   158→  const gridRows = 10; // Vertical cells
   159→  const heatmapData = useMemo(
   160→    () => generateHeatmapData(tasks, totalDays, trainCount, gridCols, gridRows),
   161→    [tasks, totalDays, trainCount, gridCols, gridRows]
   162→  );
   163→
   164→  // Find max value for normalization
   165→  const maxDensity = useMemo(() => {
   166→    let max = 0;
   167→    for (const row of heatmapData) {
   168→      for (const val of row) {
   169→        if (val > max) max = val;
   170→      }
   171→    }
   172→    return max || 1; // Avoid division by zero
   173→  }, [heatmapData]);
   174→
   175→  // Calculate viewport rectangle in minimap coordinates
   176→  const viewportRect = useMemo(() => {
   177→    // Viewport dimensions in world coordinates
   178→    const viewWidth = canvasWidth / zoom;
   179→    const viewHeight = canvasHeight / zoom;
   180→
   181→    // Viewport corners in world coordinates
   182→    const viewLeft = cameraX - viewWidth / 2;
   183→    const viewRight = cameraX + viewWidth / 2;
   184→    const viewTop = cameraY + viewHeight / 2; // Y+ is up in world
   185→    const viewBottom = cameraY - viewHeight / 2;
   186→
   187→    // Convert to minimap coordinates
   188→    const left = worldToMinimap(viewLeft, 0, worldWidth, worldHeight);
   189→    const right = worldToMinimap(viewRight, 0, worldWidth, worldHeight);
   190→    const top = worldToMinimap(0, viewTop, worldWidth, worldHeight);
   191→    const bottom = worldToMinimap(0, viewBottom, worldWidth, worldHeight);
   192→
   193→    // Calculate rectangle
   194→    const x = Math.max(0, left.x);
   195→    const y = Math.max(0, top.y);
   196→    const width = Math.min(MINIMAP_WIDTH - x, right.x - left.x);
   197→    const height = Math.min(MINIMAP_HEIGHT - y, bottom.y - top.y);
   198→
   199→    return { x, y, width: Math.max(4, width), height: Math.max(4, height) };
   200→  }, [cameraX, cameraY, zoom, canvasWidth, canvasHeight, worldWidth, worldHeight]);
   201→
   202→  /**
   203→   * Handle click/drag on minimap to navigate
   204→   */
   205→  const handleMinimapInteraction = useCallback(
   206→    (clientX: number, clientY: number) => {
   207→      if (!minimapRef.current) return;
   208→
   209→      const rect = minimapRef.current.getBoundingClientRect();
   210→      const minimapX = clientX - rect.left;
   211→      const minimapY = clientY - rect.top;
   212→
   213→      // Clamp to minimap bounds
   214→      const clampedX = Math.max(0, Math.min(MINIMAP_WIDTH, minimapX));
   215→      const clampedY = Math.max(0, Math.min(MINIMAP_HEIGHT, minimapY));
   216→
   217→      // Convert to world coordinates
   218→      const { worldX, worldY } = minimapToWorld(clampedX, clampedY, worldWidth, worldHeight);
   219→
   220→      onNavigate(worldX, worldY);
   221→    },
   222→    [worldWidth, worldHeight, onNavigate]
   223→  );
   224→
   225→  const handleMouseDown = useCallback(
   226→    (e: React.MouseEvent) => {
   227→      e.preventDefault();
   228→      e.stopPropagation();
   229→      setIsDragging(true);
   230→      handleMinimapInteraction(e.clientX, e.clientY);
   231→    },
   232→    [handleMinimapInteraction]
   233→  );
   234→
   235→  const handleMouseMove = useCallback(
   236→    (e: React.MouseEvent) => {
   237→      if (isDragging) {
   238→        handleMinimapInteraction(e.clientX, e.clientY);
   239→      }
   240→    },
   241→    [isDragging, handleMinimapInteraction]
   242→  );
   243→
   244→  const handleMouseUp = useCallback(() => {
   245→    setIsDragging(false);
   246→  }, []);
   247→
   248→  // Global mouse up listener for drag release
   249→  useEffect(() => {
   250→    if (isDragging) {
   251→      const handleGlobalMouseUp = () => setIsDragging(false);
   252→      window.addEventListener('mouseup', handleGlobalMouseUp);
   253→      return () => window.removeEventListener('mouseup', handleGlobalMouseUp);
   254→    }
   255→  }, [isDragging]);
   256→
   257→  // Render heatmap cells
   258→  const cellWidth = MINIMAP_WIDTH / gridCols;
   259→  const cellHeight = MINIMAP_HEIGHT / gridRows;
   260→
   261→  // BUG-004: Minimap is now always visible (Google Maps style)
   262→  return (
   263→    <div
   264→      style={{
   265→        position: 'absolute',
   266→        bottom: 16,
   267→        right: 16,
   268→        zIndex: 100,
   269→      }}
   270→    >
   271→      <Card
   272→        elevation={2}
   273→        style={{
   274→          padding: MINIMAP_PADDING,
   275→          borderRadius: 6,
   276→        }}
   277→      >
   278→        {/* Header - no close button (Google Maps style) */}
   279→        <div
   280→          style={{
   281→            display: 'flex',
   282→            justifyContent: 'center',
   283→            alignItems: 'center',
   284→            marginBottom: 4,
   285→            fontSize: 11,
   286→            color: '#666',
   287→          }}
   288→        >
   289→          <span style={{ fontWeight: 500 }}>Minimap</span>
   290→        </div>
   291→
   292→        {/* Minimap canvas */}
   293→        <div
   294→            ref={minimapRef}
   295→            style={{
   296→              width: MINIMAP_WIDTH,
   297→              height: MINIMAP_HEIGHT,
   298→              background: MINIMAP_BG,
   299→              position: 'relative',
   300→              cursor: isDragging ? 'grabbing' : 'pointer',
   301→              borderRadius: 3,
   302→              overflow: 'hidden',
   303→            }}
   304→            onMouseDown={handleMouseDown}
   305→            onMouseMove={handleMouseMove}
   306→            onMouseUp={handleMouseUp}
   307→          >
   308→            {/* Heatmap cells */}
   309→            <svg
   310→              width={MINIMAP_WIDTH}
   311→              height={MINIMAP_HEIGHT}
   312→              style={{ position: 'absolute', top: 0, left: 0 }}
   313→            >
   314→              {heatmapData.map((row, rowIndex) =>
   315→                row.map((value, colIndex) => {
   316→                  if (value === 0) return null;
   317→                  const normalizedValue = value / maxDensity;
   318→                  return (
   319→                    <rect
   320→                      key={`${rowIndex}-${colIndex}`}
   321→                      x={colIndex * cellWidth}
   322→                      y={rowIndex * cellHeight}
   323→                      width={cellWidth}
   324→                      height={cellHeight}
   325→                      fill={interpolateColor(normalizedValue)}
   326→                      opacity={0.8}
   327→                    />
   328→                  );
   329→                })
   330→              )}
   331→            </svg>
   332→
   333→            {/* Viewport rectangle */}
   334→            <div
   335→              style={{
   336→                position: 'absolute',
   337→                left: viewportRect.x,
   338→                top: viewportRect.y,
   339→                width: viewportRect.width,
   340→                height: viewportRect.height,
   341→                background: VIEWPORT_RECT_COLOR,
   342→                border: `2px solid ${VIEWPORT_RECT_BORDER}`,
   343→                borderRadius: 2,
   344→                pointerEvents: 'none',
   345→                boxSizing: 'border-box',
   346→              }}
   347→            />
   348→          </div>
   349→
   350→          {/* Scale indicator */}
   351→          <div
   352→            style={{
   353→              marginTop: 4,
   354→              fontSize: 10,
   355→              color: '#999',
   356→              textAlign: 'center',
   357→            }}
   358→          >
   359→            10 years × {trainCount} trains
   360→          </div>
   361→        </Card>
   362→    </div>
   363→  );
   364→}
