import { quadtree } from 'd3-quadtree';

// Build index once on mount
const taskTree = useMemo(() => {
  const tree = quadtree<TaskRender>();
  tasks.forEach(t => {
    const x = t.startDay * pxPerDay;
    const y = -t.trainIndex * pxPerTrain;
    tree.add({ ...t, x, y });
  });
  return tree;
}, [tasks]);

// Use for viewport culling (every frame)
function getVisibleTasks(viewportBounds: Bounds): TaskRender[] {
  const visible: TaskRender[] = [];

  taskTree.visit((node) => {
    const { x0, y0, x1, y1 } = node;

    // Bounding box intersection test
    if (x1 < viewportBounds.left || x0 > viewportBounds.right ||
        y1 < viewportBounds.bottom || y0 > viewportBounds.top) {
      return true; // Skip this branch
    }

    // Leaf node - collect tasks
    if (!node.length) {
      if (node.data) visible.push(node.data);
    }
  });

  return visible;
}
```

**Migration Complexity:** **HIGH**
