function addDays(date: Date, days: number): Date {
  const d = typeof date === 'string' ? new Date(date) : new Date(date);
  d.setDate(d.getDate() + days);
  return d;
}

function advanceUnit(date: Date, granularity: Granularity): Date {
  const result = new Date(date);

  switch(granularity) {
    case 'year':
      result.setFullYear(result.getFullYear() + 1);
      break;
    case 'month':
      result.setMonth(result.getMonth() + 1);
      break;
    // ... etc
  }

  return result;
}
```

**Note:** D3 doesn't have built-in date utilities (uses `d3-time`). However, `date-fns` is more suitable here.

| Aspect | Current | Alternative | Benefits |
|--------|---------|--------------|----------|
| **Timezone Bugs** | New Date() assumes local time | `d3-time-format` + UTC | Handles DST, leap seconds |
| **Unit Advancement** | Manual switch statements | Declarative with `d3.timeYear`, `d3.timeMonth` | Composable, testable |
| **Parsing** | ISO string → Date | `d3.timeParse()` | Robust, formatstring-based |

**Proposed D3 Usage:**
