import { timeFormat } from 'd3-time-format';

// Replace advanceUnit
const unitAdvancers = {
  year: d => timeYear.offset(d, 1),
  month: d => timeMonth.offset(d, 1),
  week: d => timeWeek.offset(d, 1),
  day: d => timeDay.offset(d, 1),
};

const nextDate = unitAdvancers[granularity](currentDate);

// Replace formatDate
const formatters = {
  year: timeFormat('%Y'),
  month: timeFormat('%b %Y'),
  week: timeFormat('%b %d'),
  day: timeFormat('%a, %b %d'),
};
```

**Migration Complexity:** **LOW-MEDIUM**
- Replaces switch/case with map lookup
- Benefit: Handles edge cases (Feb 29, year boundary), composable

